def tropical_add(a, b):
    return max(a, b)

def tropical_multiply(a, b):
    return a + b

def tropical_matrix_multiply(A, B):
    n = len(A)
    C = [[float('-inf')] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            for k in range(n):
                C[i][j] = max(C[i][j], A[i][k] + B[k][j])
    return C

