class Sheaf:
    def __init__(self, space, sections_fn, restriction_fn):
        self.space = space
        self.sections = sections_fn
        self.restrict = restriction_fn

    def can_glue(self, open_cover, local_sections):
        """Do local sections agree on overlaps?"""
        for i, (U, s_i) in enumerate(zip(open_cover, local_sections)):
            for j, (V, s_j) in enumerate(zip(open_cover, local_sections)):
                if i >= j:
                    continue
                overlap = U & V
                if overlap and self.restrict(s_i, overlap) != self.restrict(s_j, overlap):
                    return False  # obstruction detected
        return True

    def glue(self, open_cover, local_sections):
        """If sections agree on overlaps, produce the unique global section."""
        assert self.can_glue(open_cover, local_sections)
        return self._assemble(open_cover, local_sections)

