import numpy as np

def geometric_product(a, b, metric=None):
    """ab = a·b + a∧b"""
    if metric is None:
        metric = np.eye(len(a))
    inner = a @ metric @ b  # the symmetric part
    n = len(a)
    outer = {}
    for i in range(n):
        for j in range(i+1, n):
            outer[(i,j)] = a[i]*b[j] - a[j]*b[i]  # the antisymmetric part
    return {'grade_0': inner, 'grade_2': outer}

# The unification: ab = a·b + a∧b
# One product. All of geometry.
